args.command:
python3 -c "
import json
harness_completions = 0
with open('.yoyo/state/events.jsonl') as f:
    for line in f:
        line = line.strip()
        if not line:
            continue
        try:
            event = json.loads(line)
        except json.JSONDecodeError:
            continue
        eid = event.get('event_id', '')
        if eid.startswith('evt-harness-') and event.get('event_type') == 'ModelCallCompleted':
            harness_completions += 1
            p = event.get('payload', {})
            if harness_completions <= 5:
                print(f'  {eid}: in={p.get(\"input_tokens\")} out={p.get(\"output_tokens\")} cache_read={p.get(\"cache_read_input_tokens\")} cache_write={p.get(\"cache_creation_input_tokens\")} retroactive={p.get(\"retroactive\")}')
print(f'Total evt-harness- ModelCallCompleted: {harness_completions}')
"

